import React from 'react';
import Header from './components/Header';
import Hero from './components/Hero';
import Marquee from './components/Marquee';
import DreamSmiles from './components/DreamSmiles';
import Results from './components/Results';
import WhyWhistle from './components/WhyWhistle';
import WhistleDifference from './components/WhistleDifference';
import Comparison from './components/Comparison';
import FourSteps from './components/FourSteps';
import DoctorLed from './components/DoctorLed';
import HappySmilers from './components/HappySmilers';
import FAQ from './components/FAQ';
import Footer from './components/Footer';

export default function App() {
  return (
    <>
      <Header />
      <Hero />
      <Marquee />
      <DreamSmiles />
      <Results />
      <WhyWhistle />
      <WhistleDifference />
      <Comparison />
      <FourSteps />
      <DoctorLed />
      <HappySmilers />
      <FAQ />
      <Footer />
    </>
  );
}
